package log

import (
	"io"
	"runtime"
)

// CRLFWriter is an io.Writer that converts LF to CRLF on Windows.
// It preserves existing CRLF sequences and handles partial writes correctly.
type CRLFWriter struct {
	writer io.Writer
	// last is used to track if the previous write ended with \r,
	// which helps detect existing CRLF sequences that span multiple writes.
	last byte
}

// NewCRLFWriter returns a new CRLFWriter that wraps the given writer.
// On non-Windows platforms, it returns the writer as-is.
func NewCRLFWriter(w io.Writer) io.Writer {
	if runtime.GOOS != "windows" {
		return w
	}
	return &CRLFWriter{writer: w}
}

// Write implements io.Writer and converts LF to CRLF.
// It ensures that:
// - Single \n is converted to \r\n
// - Existing \r\n sequences are preserved
// - Works correctly when writes are partial (e.g., \r written in one call, \n in another)
func (w *CRLFWriter) Write(p []byte) (int, error) {
	if len(p) == 0 {
		return 0, nil
	}

	// Buffer to collect the converted bytes
	buf := make([]byte, 0, len(p)*2)

	for _, b := range p {
		if b == '\n' && w.last != '\r' {
			// Single LF without preceding CR - add CR before LF
			buf = append(buf, '\r', '\n')
		} else {
			buf = append(buf, b)
		}
		w.last = b
	}

	// Write the converted buffer to the underlying writer
	_, err := w.writer.Write(buf)
	if err != nil {
		return 0, err
	}

	// Return the original length as per io.Writer contract
	return len(p), nil
}

